THE RISK:
{
 "id": "firmware-audit-and-poc-attrition",
 "title": "An intelligent PDU is a networked device: the security-audit gate precedes every listing, and a third of deployed pilots never convert to accepted revenue",
 "narrative": "'Intelligent' is the product's differentiator and its hidden tax. A networked PDU with remote management enters the buyer's attack surface, so operators audit the vendor's firmware-signing, vulnerability-disclosure and update infrastructure BEFORE listing — a gate that precedes the first PO and appears nowhere in the funnel. The venture must stand up this infrastructure (secure OTA, SBOM, disclosure policy) during the same year it is supposed to harvest. And clearing the gate isn't the end: POC-stage industrial hardware shows ~30% of deployed systems never reaching acceptance — customers sign, vendors deploy, and the hardware comes back months later. Both effects hit realized Year-1 revenue after the demand, the reach, and even the PO exist, which is why no market-sizing band captures them.",
 "category": "execution",
 "targetNodes": [
  "obtainableFactor"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "Buyer security review of networked power hardware (firmware update path, SBOM, disclosure process) is a pre-listing gate for the intelligent-PDU product class; the pre-launch venture has no audited update infrastructure on day 1",
   "refs": [
    "profile:Product",
    "profile:Stage",
    "digest:serviceable-benchmark#c12"
   ]
  },
  {
   "step": "propagation",
   "text": "Deals that clear the gate still attrit: ~30% of deployed POC-stage industrial systems are never fully accepted, so booked pilots overstate realized revenue by a large margin in the first year",
   "refs": [
    "digest:obtainable-benchmark#c8",
    "digest:obtainable-benchmark#c9"
   ]
  },
  {
   "step": "model-impact",
   "text": "Realized Year-1 obtainable share is materially below the pipeline-implied share even at constant win rates — obtainableFactor overstates what converts to accepted, invoiced revenue inside the window",
   "refs": [
    "ledger:obtainableFactor"
   ]
  }
 ],
 "whyMissable": "Security review and pilot acceptance live downstream of everything a market model measures — demand, reach, even signed POs. The founder's risk list covers 'can we sell it'; this risk is 'does what we sold count', and the surface signal (a signed pilot) actively reassures. The intelligence features driving the value proposition are the same ones creating the gate.",
 "expectedObviousness": "low",
 "falsifier": "Two CE operator or colo security reviews passed pre-launch (documented sign-off on the firmware/update stack), plus first pilot cohort showing >90% acceptance-to-invoice conversion within two quarters of deployment.",
 "likelihood": {
  "value": 0.48,
  "rationale": "The 30% non-acceptance figure is a documented POC-stage base rate for industrial hardware, and networked-device security gating at DC operators is standard practice; uncertainty is whether a rack PDU's blast radius triggers full-depth audits at mid-size buyers or only at large operators. [evidence revision: Both load-bearing premises are corroborated by independent sources: networked-PDU security auditing is documented industry practice (third-party VAPT, SBOM, OCP-SAFE) and pilot-to-production attrition base rates are well-established and arguably higher than the 30% assumed. The residual uncertainty flagged in the original rationale — whether audits reach full depth at mid-size vs. large operators — remains unresolved, so I raise only modestly rather than to a high value.]",
  "basis": "evidence",
  "revisedFrom": 0.4
 },
 "perturbation": [
  {
   "nodeId": "obtainableFactor",
   "op": "scale",
   "value": 0.7,
   "note": "Pilot-to-accepted-revenue attrition plus security-gate delays erode realized Year-1 capture by ~30%"
  }
 ],
 "indicators": [
  {
   "signal": "Cybersecurity requirements (SBOM, signed firmware, vulnerability-disclosure policy) appearing as mandatory line items in DC fit-out and rack-power RFQs",
   "where": "TED (Tenders Electronic Daily) DC procurement notices; large-operator supplier security questionnaires",
   "threshold": "Security annex mandatory in ≥half of sampled rack-power RFQs",
   "updates": "increases"
  },
  {
   "signal": "Regulatory hardening of connected-device requirements applicable to networked PDUs (RED cybersecurity delegated act enforcement; Cyber Resilience Act transition dates)",
   "where": "Official Journal of the EU / Commission standards dockets on RED 2022/30 and CRA implementation",
   "threshold": "CRA conformity dates confirmed inside the venture's Year-1 window",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Survey the actual security-review requirements of 5 target CE buyers (questionnaires, audit depth, pass criteria) before finalizing the launch feature set",
   "type": "information",
   "voiNodeId": "obtainableFactor",
   "note": "Establishes whether the gate is questionnaire-deep or audit-deep per buyer tier — the difference is a quarter of runway"
  },
  {
   "action": "Build and third-party-attest the firmware-signing/OTA/SBOM stack pre-launch, and package the attestation as a sales asset",
   "type": "operational",
   "voiNodeId": null,
   "note": "Turns the gate into a differentiator against slower-moving incumbents' legacy firmware practices"
  },
  {
   "action": "Write acceptance criteria and conversion milestones into every pilot contract (defined test period, auto-conversion clause, partial payment on deployment)",
   "type": "contractual",
   "voiNodeId": null,
   "note": "Directly attacks the 30% never-accepted attrition mode"
  }
 ],
 "evidenceStatus": "corroborated",
